                            mov         [rbp - 24], rax     ; args array ptr = NULL
                            mov         [rbp - 32], rdx     ; save start
                            xor         eax, eax
                            mov         [rbp - 16], eax        ; sub_cs_acc = 0
                            mov         eax, [rbp - 32]       ; start value
                            cmp         eax, 0
                            jge         pl_main_sl_0_c0_α
                            jmp         pl_main_sl_0_ω

; --- clause 1/1  n_vars=3 body_ucalls=1 ---
; clause 0 entry
pl_main_sl_0_c0_α:
                            mov         rdi, 0
                            call        term_new_var
                            mov         [rbp - 56], rax    ; var slot 0
                            mov         rdi, 1
                            call        term_new_var
                            mov         [rbp - 64], rax    ; var slot 1
                            mov         rdi, 2
                            call        term_new_var
                            mov         [rbp - 72], rax    ; var slot 2
                            lea         rdi, [rel pl_trail]
                            call        trail_mark_fn
                            mov         [rbp - 8], eax          ; clause trail mark
                            mov         dword [rbp - 40], 0  ; init sub_cs slot 0
pl_main_sl_0_c0_body:
                            lea         rdi, [rel pl_trail]
                            call        trail_mark_fn
                            mov         [rbp - 48], eax     ; UCALL_MARK_OFFSET(0) = β0 unwind target
; re-entry decode: inner = start - 0
                            mov         eax, [rbp - 32]        ; start
                            sub         eax, 0                ; inner = start - base
                            jle         pl_main_sl_0_c0_body_fresh
                            dec         eax                    ; inner - 1 = packed sub_cs
                            mov         ecx, eax               ; work register
                            mov         edx, ecx
                            and         edx, 4095        ; ucall 0 sub_cs = packed % STRIDE
                            mov         [rbp - 40], edx    ; pre-load slot 0
; fall into α0 — it restores edx from slot 0
                            jmp         pl_main_sl_0_c0_α0
pl_main_sl_0_c0_body_fresh:
                            xor         edx, edx               ; sub_cs=0 for first ucall
pl_main_sl_0_c0_α0:
                            sub         rsp, 16              ; args array for atom_codes/2
                            mov         rbx, rsp               ; stable base (immune to rsp shifts)
                            lea         rax, [rel pl_atom_123_2]
                            mov         [rbx + 0], rax    ; args[0]
                            mov         rax, [rbp - 56]  ; var slot 0 (_V0)
                            mov         [rbx + 8], rax    ; args[1]
                            mov         rdi, rbx               ; args[] ptr
                            lea         rsi, [rel pl_trail]
                            mov         edx, [rbp - 40]    ; restore sub_cs ucall 0
                            call        pl_atom_codes_sl_2_r
                            add         rsp, 16
                            test        eax, eax
                            js          pl_main_sl_0_c0_β0
                            mov         [rbp - 40], eax        ; ucall slot 0 sub_cs
                            jmp         pl_main_sl_0_c0_γ0
pl_main_sl_0_c0_β0:
                            lea         rdi, [rel pl_trail]
                            mov         esi, [rbp - 48]    ; unwind to before ucall 0
                            call        trail_unwind
                            jmp         pl_main_sl_0_ω
pl_main_sl_0_c0_γ0:
                            mov         eax, [rbp - 40]    ; sub_cs_acc = slot 0
                            mov         [rbp - 16], eax    ; store recomputed sub_cs_acc
                            xor         edx, edx               ; next ucall starts fresh
                            mov         dword [rbp - 32], 0    ; _cs
disj_main_sl_0_0_1_retry:
                            sub         rsp, 32
                            sub         rsp, 16            ; args[2] for compound phrase/2
                            sub         rsp, 8            ; args[1] for compound digits/1
                            mov         rax, [rbp - 64]  ; var slot 1 (_V1)
                            mov         [rsp + 0], rax  ; compound arg 0
                            mov         edi, dword [rel pl_atom_digits_4 + 8]  ; functor atom_id
                            mov         esi, 1                   ; arity
                            mov         rdx, rsp                   ; args ptr
                            call        term_new_compound
                            add         rsp, 8
                            mov         [rsp + 0], rax  ; compound arg 0
                            mov         rax, [rbp - 56]  ; var slot 0 (_V0)
                            mov         [rsp + 8], rax  ; compound arg 1
                            mov         edi, dword [rel pl_atom_phrase_3 + 8]  ; functor atom_id
                            mov         esi, 2                   ; arity
                            mov         rdx, rsp                   ; args ptr
                            call        term_new_compound
                            add         rsp, 16
                            mov         [rsp + 0], rax
                            sub         rsp, 16            ; args[2] for compound atom_codes/2
                            mov         rax, [rbp - 72]  ; var slot 2 (_V2)
                            mov         [rsp + 0], rax  ; compound arg 0
                            mov         rax, [rbp - 64]  ; var slot 1 (_V1)
                            mov         [rsp + 8], rax  ; compound arg 1
                            mov         edi, dword [rel pl_atom_atom_codes_5 + 8]  ; functor atom_id
                            mov         esi, 2                   ; arity
                            mov         rdx, rsp                   ; args ptr
                            call        term_new_compound
                            add         rsp, 16
                            mov         [rsp + 8], rax
