                            jmp         disj_main_sl_0_0_1_retry
                            jmp         disj_main_sl_0_0_1_done
disj_main_sl_0_0_1_else:
                            sub         rsp, 16
                            lea         rax, [rel pl_atom_fail_7]
                            mov         [rsp + 0], rax
                            mov         rdi, rsp
                            lea         rsi, [rel pl_trail]
