                            inc         eax                   ; sub_cs + 1
                            add         eax, 0               ; + base
                            mov         rsp, rbp
                            pop         rbp
                            ret

pl_main_sl_0_ω:
; ω — all clauses exhausted
                            lea         rdi, [rel pl_trail]
                            mov         esi, [rbp - 8]         ; trail mark
                            call        trail_unwind
                            mov         rsp, rbp
                            pop         rbp
                            mov         eax, -1
                            ret

global pl_main_sl_0
pl_main_sl_0:
; single-shot wrapper: push start=0
                            xor         rdx, rdx
                            jmp         pl_main_sl_0_r

; ============================================================
; pl_rt_init — fix up atom_ids in .data Term structs
; ============================================================
pl_rt_init:
                            push        rbp
                            mov         rbp, rsp
                            lea         rdi, [rel pl_astr_0]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom___0 + 8], eax
                            lea         rdi, [rel pl_astr_1]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom____1 + 8], eax
                            lea         rdi, [rel pl_astr_2]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom_123_2 + 8], eax
                            lea         rdi, [rel pl_astr_3]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom_phrase_3 + 8], eax
                            lea         rdi, [rel pl_astr_4]
