                            mov         dword [rel pl_atom_digits_4 + 8], eax
                            lea         rdi, [rel pl_astr_5]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom_atom_codes_5 + 8], eax
                            lea         rdi, [rel pl_astr_6]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom_write_6 + 8], eax
                            lea         rdi, [rel pl_astr_7]
                            call        prolog_atom_intern
                            mov         dword [rel pl_atom_fail_7 + 8], eax
                            pop         rbp
                            ret

; ============================================================
; main
; ============================================================
main:
                            push        rbp
                            mov         rbp, rsp
; init atom table
                            call        prolog_atom_init
; init trail
                            lea         rdi, [rel pl_trail]
                            call        trail_init
; fix up atom_id fields
                            call        pl_rt_init
; call initialization predicate: main/0
                            xor         rdi, rdi               ; args=NULL (arity 0)
                            lea         rsi, [rel pl_trail]   ; Trail*
                            xor         edx, edx               ; start=0
                            call        pl_main_sl_0_r
; exit 0
                            xor         edi, edi
                            call        exit
                            pop         rbp
                            ret

